values
('additional-maths:10-1-kinematics:mcq:5d86d83a', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "A particle has velocity \\( v = 4t^2 - 3 \\). Find its acceleration \\( a \\).", "options": ["\\( 8t \\)", "\\( 8t - 3 \\)", "\\( \\frac{4t^3}{3} - 3t \\)", "\\( 8 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( a = \\frac{dv}{dt} = 8t \\). The constant \\( -3 \\) differentiates to 0; the third option integrates by mistake."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:32105410', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "A particle has \\( a = 12t - 6 \\) and \\( v = 2 \\) when \\( t = 0 \\). Find \\( v \\).", "options": ["\\( 6t^2 - 6t + 2 \\)", "\\( 6t^2 - 6t \\)", "\\( 12 \\)", "\\( 6t^2 - 6t + c \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( v = \\int (12t-6)\\,dt = 6t^2 - 6t + c \\); \\( v = 2 \\) at \\( t = 0 \\) gives \\( c = 2 \\). The second option forgets the constant; the last leaves it unevaluated."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:a7882466', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "A particle is momentarily at rest when:", "options": ["\\( v = 0 \\)", "\\( a = 0 \\)", "\\( s = 0 \\)", "\\( \\frac{da}{dt} = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "At rest means the velocity is zero. \\( a = 0 \\) is where the velocity is a maximum or minimum, not where it is zero."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:69e01e26', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "The velocity of a particle is a maximum when:", "options": ["\\( a = \\frac{dv}{dt} = 0 \\)", "\\( v = 0 \\)", "\\( s = 0 \\)", "\\( t = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "Velocity is stationary (max or min) where its rate of change, the acceleration, is zero."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:c3a465de', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "A particle has velocity \\( v = 15t - 3t^2 \\). At what time is its velocity greatest?", "options": ["\\( t = 2.5 \\) s", "\\( t = 5 \\) s", "\\( t = 0 \\) s", "\\( t = 7.5 \\) s"]}'::jsonb, '{"answer": 0, "explain": "\\( a = 15 - 6t = 0 \\Rightarrow t = 2.5 \\) s. (\\( t = 5 \\) is when \\( v = 0 \\).)"}'::jsonb),
('additional-maths:10-1-kinematics:mcq:41301bdc', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "The maximum acceleration of a particle whose acceleration is \\( a = \\frac{1}{100}(30t - 3t^2) \\) occurs when:", "options": ["\\( \\frac{da}{dt} = 0 \\)", "\\( a = 0 \\)", "\\( v = 0 \\)", "\\( t = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "Maximum acceleration is a turning point of \\( a \\), so set \\( \\frac{da}{dt} = 0 \\). Setting \\( a = 0 \\) finds where the acceleration vanishes, not where it is greatest."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:e0bd3699', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "The suvat formula \\( s = ut + \\tfrac{1}{2}at^2 \\) may be used:", "options": ["Only when the acceleration is constant", "For any motion whatsoever", "Only when the particle starts from rest", "Only for the first second of motion"]}'::jsonb, '{"answer": 0, "explain": "The suvat formulae assume a constant (uniform) acceleration. If \\( a \\) varies with time you must use calculus."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:4899bf19', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "A car''s velocity is \\( v = t^2 + 2t \\). A student uses \\( v = u + at \\) to find the velocity at \\( t = 3 \\). What is wrong?", "options": ["The acceleration \\( a = 2t + 2 \\) is not constant, so suvat cannot be used", "Nothing — the method is fine", "They should use \\( v^2 = u^2 + 2as \\) instead", "They forgot to add a constant of integration"]}'::jsonb, '{"answer": 0, "explain": "Here \\( a = \\frac{dv}{dt} = 2t + 2 \\), which changes with time. suvat needs constant acceleration, so this is invalid — just substitute \\( t = 3 \\) into \\( v \\) directly."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:a1d5f734', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "A particle has velocity \\( v = 3t^2 \\) m s⁻¹. What distance does it travel between \\( t = 0 \\) and \\( t = 2 \\) s?", "options": ["8 m", "8 m s⁻¹", "12 m", "24 m"]}'::jsonb, '{"answer": 0, "explain": "Distance \\( = \\int_0^2 3t^2\\,dt = [t^3]_0^2 = 8 \\) m. The units are metres, not m s⁻¹; option 3 differentiates by mistake."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:f710edbb', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "Acceleration can be described as:", "options": ["The second derivative of displacement with respect to time", "The integral of velocity", "The first derivative of displacement", "Displacement divided by time"]}'::jsonb, '{"answer": 0, "explain": "\\( a = \\frac{dv}{dt} = \\frac{d^2s}{dt^2} \\): differentiate displacement twice. The first derivative of \\( s \\) is velocity."}'::jsonb),
('additional-maths:10-1-kinematics:mcq:49169362', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'mcq', 'mcq', 1, '{"question": "A body accelerates uniformly from rest at \\( 2 \\) m s⁻² for \\( 5 \\) s. Find its final velocity.", "options": ["10 m s⁻¹", "10 m", "25 m s⁻¹", "20 m s⁻¹"]}'::jsonb, '{"answer": 0, "explain": "Constant acceleration, so use \\( v = u + at = 0 + 2 \\times 5 = 10 \\) m s⁻¹. The units are m s⁻¹, not m."}'::jsonb),
('additional-maths:10-1-kinematics:tf:c5489d93', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "Velocity is the rate of change of displacement, \\( v = \\frac{ds}{dt} \\)."}'::jsonb, '{"answer": true, "explain": "Yes — differentiate displacement to get velocity, and differentiate again for acceleration."}'::jsonb),
('additional-maths:10-1-kinematics:tf:88f622f6', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "To find the acceleration from the velocity you integrate the velocity."}'::jsonb, '{"answer": false, "explain": "You differentiate: \\( a = \\frac{dv}{dt} \\). Integrating velocity gives displacement."}'::jsonb),
('additional-maths:10-1-kinematics:tf:1104e1e2', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "The suvat formulae can be used whenever an object is moving."}'::jsonb, '{"answer": false, "explain": "Only when the acceleration is constant. If \\( a \\) varies with time you must use calculus."}'::jsonb),
('additional-maths:10-1-kinematics:tf:97e71cb5', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "When you integrate acceleration to find velocity you must add a constant of integration."}'::jsonb, '{"answer": true, "explain": "Yes, and you then find its value from an initial condition such as the velocity at \\( t = 0 \\)."}'::jsonb),
('additional-maths:10-1-kinematics:tf:10c89db0', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "A particle is momentarily at rest when its acceleration is zero."}'::jsonb, '{"answer": false, "explain": "At rest means \\( v = 0 \\). Zero acceleration is where the velocity is a maximum or minimum."}'::jsonb),
('additional-maths:10-1-kinematics:tf:3457380f', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "The kinematics calculus relations and the suvat set are both printed on the exam formula sheet."}'::jsonb, '{"answer": true, "explain": "Both are PROVIDED — but you still must know when and how to use each."}'::jsonb),
('additional-maths:10-1-kinematics:tf:7ce14013', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "The velocity of a particle is a maximum where \\( \\frac{dv}{dt} = 0 \\)."}'::jsonb, '{"answer": true, "explain": "Velocity is stationary where its rate of change (the acceleration) is zero."}'::jsonb),
('additional-maths:10-1-kinematics:tf:14946b3f', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tf', 'tf', 1, '{"question": "If a particle''s velocity is \\( v = 5t^2 - 2t \\), then its acceleration is constant."}'::jsonb, '{"answer": false, "explain": "\\( a = \\frac{dv}{dt} = 10t - 2 \\), which changes with time — the acceleration is variable, so suvat cannot be used."}'::jsonb),
('additional-maths:10-1-kinematics:learn:a275250d', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'learn', 'mcq', 1, '{"readingTitle": "What do displacement, velocity and acceleration mean, and how are they linked?", "reading": "<p><strong>Kinematics</strong> is the study of motion. In this course a particle always moves in a <strong>straight line</strong>, and three quantities describe it:</p>\n            <ul>\n              <li><strong>Displacement</strong> \\( s \\) — its position measured from a fixed point, in metres (m). Displacement has a <em>direction</em>, so it can be negative.</li>\n              <li><strong>Velocity</strong> \\( v \\) — the rate of change of displacement, in m s⁻¹. A negative velocity means moving in the negative direction.</li>\n              <li><strong>Acceleration</strong> \\( a \\) — the rate of change of velocity, in m s⁻². A negative acceleration is a <strong>deceleration</strong> (slowing down).</li>\n            </ul>\n            <p>They are linked by <strong>calculus</strong>. Going <em>down</em> the chain you differentiate; going <em>up</em> you integrate:</p>\n            <p>\\[ v = \\frac{ds}{dt}, \\qquad a = \\frac{dv}{dt} = \\frac{d^2s}{dt^2}, \\qquad v = \\int a\\,dt, \\qquad s = \\int v\\,dt. \\]</p>\n            <p>These four relations are <strong>PROVIDED</strong> on the exam formula sheet — you do not need to memorise them, but you must know how to use them. <strong>Always give units</strong> with every answer.</p>", "question": "Which quantity is equal to \\( \\frac{ds}{dt} \\)?", "options": ["Velocity", "Acceleration", "Displacement", "Distance per bump"]}'::jsonb, '{"answer": 0, "explain": "Velocity is the rate of change of displacement, so \\( v = \\frac{ds}{dt} \\). Differentiating velocity again gives acceleration."}'::jsonb),
('additional-maths:10-1-kinematics:learn:a229a094', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'learn', 'mcq', 1, '{"readingTitle": "How do you go from displacement to velocity to acceleration?", "reading": "<p>Given displacement as a function of time, <strong>differentiate to get velocity, then differentiate again to get acceleration</strong>. Use the ordinary rule for \\( x^n \\): multiply by the power, reduce the power by 1.</p>\n            <p><strong>Worked example — a particle has \\( s = t^3 - 6t^2 + 9t \\) metres at time \\( t \\) seconds:</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Differentiate for velocity: \\( v = \\dfrac{ds}{dt} = 3t^2 - 12t + 9 \\) m s⁻¹.</td></tr>\n              <tr><td>2. Differentiate again for acceleration: \\( a = \\dfrac{dv}{dt} = 6t - 12 \\) m s⁻².</td></tr>\n              <tr><td>3. At \\( t = 4 \\): \\( v = 48 - 48 + 9 = 9 \\) m s⁻¹ and \\( a = 24 - 12 = 12 \\) m s⁻².</td></tr>\n            </table>\n            <p>Notice the constant term of \\( s \\) disappears on differentiating, and every unit changes as you go down the chain (m → m s⁻¹ → m s⁻²).</p>", "question": "If \\( v = 3t^2 - 12t + 9 \\), find the acceleration when \\( t = 3 \\).", "options": ["6 m s⁻²", "0 m s⁻²", "18 m s⁻²", "9 m s⁻²"]}'::jsonb, '{"answer": 0, "explain": "\\( a = \\frac{dv}{dt} = 6t - 12 \\); at \\( t = 3 \\), \\( a = 18 - 12 = 6 \\) m s⁻²."}'::jsonb),
('additional-maths:10-1-kinematics:learn:261a1424', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'learn', 'mcq', 1, '{"readingTitle": "How do you go back from acceleration or velocity to displacement?", "reading": "<p>Going <em>up</em> the chain you <strong>integrate</strong>. Every integration introduces a <strong>constant of integration</strong> \\( + c \\), and you find its value from an <strong>initial condition</strong> (a known velocity or displacement, usually at \\( t = 0 \\)). Forgetting the \\( + c \\) is the single most common error here.</p>\n            <p><strong>Worked example — a particle has acceleration \\( a = 10 - 2t \\) m s⁻², with velocity 3 m s⁻¹ and displacement 0 when \\( t = 0 \\). Find \\( v \\) and \\( s \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Integrate \\( a \\): \\( v = \\int (10 - 2t)\\,dt = 10t - t^2 + c \\).</td></tr>\n              <tr><td>2. Use \\( v = 3 \\) at \\( t = 0 \\): \\( 3 = 0 - 0 + c \\Rightarrow c = 3 \\), so \\( v = 10t - t^2 + 3 \\) m s⁻¹.</td></tr>\n              <tr><td>3. Integrate \\( v \\): \\( s = \\int (10t - t^2 + 3)\\,dt = 5t^2 - \\dfrac{t^3}{3} + 3t + k \\).</td></tr>\n              <tr><td>4. Use \\( s = 0 \\) at \\( t = 0 \\): \\( k = 0 \\), so \\( s = 5t^2 - \\dfrac{t^3}{3} + 3t \\) m.</td></tr>\n            </table>\n            <p>Sanity check: differentiate your \\( s \\) and you should get back the \\( v \\) you started with.</p>", "question": "A particle has \\( a = 6t - 4 \\) and \\( v = 5 \\) when \\( t = 0 \\). Find \\( v \\).", "options": ["\\( 3t^2 - 4t + 5 \\)", "\\( 3t^2 - 4t \\)", "\\( 6 \\)", "\\( 3t^2 - 4t + c \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( v = \\int (6t-4)\\,dt = 3t^2 - 4t + c \\); using \\( v = 5 \\) at \\( t = 0 \\) gives \\( c = 5 \\). You must evaluate the constant, not leave it as \\( c \\)."}'::jsonb),
('additional-maths:10-1-kinematics:learn:73ffed54', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'learn', 'mcq', 1, '{"readingTitle": "How do you interpret motion — at rest, maximum velocity, maximum acceleration?", "reading": "<p>Many marks are for <strong>interpreting</strong> the calculus in context. The key facts:</p>\n            <ul>\n              <li>A particle is <strong>momentarily at rest</strong> when \\( v = 0 \\).</li>\n              <li>The <strong>velocity is a maximum (or minimum)</strong> when \\( a = \\dfrac{dv}{dt} = 0 \\) — velocity is stationary, so its rate of change is zero.</li>\n              <li>The <strong>acceleration is a maximum</strong> when \\( \\dfrac{da}{dt} = 0 \\) — a turning point of \\( a \\) itself. It is <em>not</em> where \\( a = 0 \\).</li>\n            </ul>\n            <p><strong>Worked example — a particle has \\( v = 12t - 3t^2 \\) m s⁻¹ for \\( t \\ge 0 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. At rest: \\( 12t - 3t^2 = 3t(4 - t) = 0 \\Rightarrow t = 0 \\) or \\( t = 4 \\) s.</td></tr>\n              <tr><td>2. Maximum velocity: \\( a = \\dfrac{dv}{dt} = 12 - 6t = 0 \\Rightarrow t = 2 \\) s.</td></tr>\n              <tr><td>3. That velocity is \\( v = 12(2) - 3(2)^2 = 24 - 12 = 12 \\) m s⁻¹.</td></tr>\n            </table>\n            <p>Because \\( a = 12 - 6t \\) is positive before \\( t = 2 \\) and negative after, the velocity really is a maximum there.</p>", "question": "For \\( v = 15t - 3t^2 \\), at what time is the velocity a maximum?", "options": ["\\( t = 2.5 \\) s", "\\( t = 5 \\) s", "\\( t = 0 \\) s", "\\( t = 7.5 \\) s"]}'::jsonb, '{"answer": 0, "explain": "Maximum velocity is where \\( a = \\frac{dv}{dt} = 15 - 6t = 0 \\), giving \\( t = 2.5 \\) s. (\\( t = 5 \\) is where \\( v = 0 \\), i.e. at rest.)"}'::jsonb),
('additional-maths:10-1-kinematics:learn:dad8c6ec', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'learn', 'mcq', 1, '{"readingTitle": "When can you use the suvat formulae instead of calculus?", "reading": "<p>The <strong>suvat</strong> (constant-acceleration) formulae may be used <strong>only when the acceleration is constant</strong> (uniform). They are also <strong>PROVIDED</strong> on the formula sheet:</p>\n            <p>\\[ v = u + at, \\quad s = ut + \\tfrac{1}{2}at^2, \\quad s = \\tfrac{1}{2}(u+v)t, \\quad v^2 = u^2 + 2as, \\quad s = vt - \\tfrac{1}{2}at^2. \\]</p>\n            <ul>\n              <li>Here \\( u \\) is the <strong>initial</strong> velocity, \\( v \\) the <strong>final</strong> velocity, \\( a \\) the constant acceleration, \\( s \\) the displacement and \\( t \\) the time.</li>\n              <li><strong>How to spot which method:</strong> if a problem says \"uniform / constant acceleration\" (or \"decelerates uniformly\"), use suvat. If the velocity or acceleration is given as a <strong>function of \\( t \\)</strong> (e.g. \\( v = t^2 - 3t \\)), the acceleration <em>varies</em>, so suvat does not apply — you must differentiate or integrate.</li>\n            </ul>\n            <p><strong>Worked example (constant acceleration) — a train starts from rest and accelerates uniformly to 24 m s⁻¹ in 12 s:</strong> using \\( v = u + at \\) with \\( u = 0 \\): \\( 24 = 0 + a(12) \\Rightarrow a = 2 \\) m s⁻². The distance is \\( s = \\tfrac{1}{2}(u+v)t = \\tfrac{1}{2}(24)(12) = 144 \\) m.</p>", "question": "In which situation can you use \\( v^2 = u^2 + 2as \\)?", "options": ["A body moving with constant acceleration", "A body whose velocity is \\( v = t^2 - 3t \\)", "A body whose acceleration is \\( a = 6t \\)", "Any moving body at all"]}'::jsonb, '{"answer": 0, "explain": "The suvat formulae need constant acceleration. If \\( v \\) or \\( a \\) is a function of \\( t \\), the acceleration varies, so you must use calculus."}'::jsonb),
('additional-maths:10-1-kinematics:learn:9e4f9031', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'learn', 'mcq', 1, '{"readingTitle": "How do you estimate velocity from a displacement–time graph? (numerical methods)", "reading": "<p>Velocity is the <strong>gradient of the displacement–time curve</strong>. When you cannot (or need not) differentiate, you can <strong>estimate</strong> that gradient numerically using a <strong>chord</strong> between two nearby points — exactly the chord-to-tangent idea from differentiation:</p>\n            <p>\\[ v \\approx \\frac{s(t_2) - s(t_1)}{t_2 - t_1}. \\]</p>\n            <p>The <strong>smaller the interval</strong>, the closer the chord gradient gets to the true (tangent) velocity.</p>\n            <p><strong>Worked example — a runner''s displacement \\( s \\) (m) is recorded near \\( t = 3 \\) s. Estimate the velocity at \\( t = 3 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>Given \\( s(3.0) = 12.00 \\), \\( s(3.2) = 13.44 \\): \\( v \\approx \\dfrac{13.44 - 12.00}{0.2} = 7.2 \\) m s⁻¹.</td></tr>\n              <tr><td>Using a smaller step \\( s(3.1) = 12.71 \\): \\( v \\approx \\dfrac{12.71 - 12.00}{0.1} = 7.1 \\) m s⁻¹.</td></tr>\n              <tr><td>The estimates are closing in on the true value, about \\( 7 \\) m s⁻¹.</td></tr>\n            </table>\n            <p>State the answer with its units and note that a smaller interval improves the estimate.</p>", "question": "A displacement–time graph gives \\( s = 20 \\) m at \\( t = 4 \\) s and \\( s = 22.4 \\) m at \\( t = 4.4 \\) s. Estimate the velocity at \\( t = 4 \\).", "options": ["6 m s⁻¹", "2.4 m s⁻¹", "0.4 m s⁻¹", "9.6 m s⁻¹"]}'::jsonb, '{"answer": 0, "explain": "Chord gradient \\( = \\frac{22.4 - 20}{4.4 - 4} = \\frac{2.4}{0.4} = 6 \\) m s⁻¹."}'::jsonb),
('additional-maths:10-1-kinematics:misc:4805c0c3', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using \\( v^2 = u^2 + 2as \\) to find a distance when the velocity is given by \\( v = \\frac{1}{100}(15t^2 - t^3) + 9 \\).</p><p><strong>✅ The correct idea:</strong> The suvat formulae only work for constant acceleration. Here \\( v \\) is a cubic in \\( t \\), so the acceleration varies — a weak answer plugs into suvat and scores nothing; a strong answer integrates: distance \\( = \\int v\\,dt \\).</p>", "question": "The velocity is \\( v = \\frac{1}{100}(15t^2 - t^3) + 9 \\). How do you find the distance travelled?", "options": ["Integrate \\( v \\) with respect to \\( t \\)", "Use \\( v^2 = u^2 + 2as \\)", "Use \\( s = ut + \\frac{1}{2}at^2 \\)", "Differentiate \\( v \\)"]}'::jsonb, '{"answer": 0, "explain": "Variable acceleration means suvat is invalid; distance is \\( \\int v\\,dt \\)."}'::jsonb),
('additional-maths:10-1-kinematics:misc:c33b70f6', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing the maximum acceleration as \"0.75\" with nothing after it.</p><p><strong>✅ The correct idea:</strong> Every kinematics answer needs its units. A weak answer gives a bare number; a strong answer writes \\( 0.75 \\) m s⁻² — the units are part of the answer and a bare number can lose the mark.</p>", "question": "What are the correct units for an acceleration?", "options": ["m s⁻²", "m s⁻¹", "m", "s"]}'::jsonb, '{"answer": 0, "explain": "Acceleration is a change of velocity per second, so its units are m s⁻² (metres per second per second)."}'::jsonb),
('additional-maths:10-1-kinematics:misc:62055647', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Integrating \\( a = 6t - 4 \\) to get \\( v = 3t^2 - 4t \\) and stopping there.</p><p><strong>✅ The correct idea:</strong> Integration always introduces \\( + c \\). A weak answer omits it; a strong answer writes \\( v = 3t^2 - 4t + c \\) and then uses the initial condition (e.g. \\( v \\) at \\( t = 0 \\)) to find \\( c \\).</p>", "question": "After integrating acceleration to find velocity, what must you do next?", "options": ["Add \\( + c \\) and find it from an initial condition", "Divide by \\( t \\)", "Differentiate the result", "Nothing else"]}'::jsonb, '{"answer": 0, "explain": "The constant of integration must be added and then evaluated from a known velocity or displacement."}'::jsonb),
('additional-maths:10-1-kinematics:misc:30c202f8', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Finding the maximum acceleration by solving \\( a = 0 \\).</p><p><strong>✅ The correct idea:</strong> The maximum acceleration is a turning point of \\( a \\), so you set \\( \\frac{da}{dt} = 0 \\). A weak answer confuses \"maximum\" with \"zero\"; a strong answer differentiates \\( a \\) again (or completes the square) to locate the maximum.</p>", "question": "To find the maximum acceleration you should:", "options": ["Set \\( \\frac{da}{dt} = 0 \\)", "Set \\( a = 0 \\)", "Set \\( v = 0 \\)", "Set \\( s = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "Maximum acceleration is where the rate of change of acceleration is zero."}'::jsonb),
('additional-maths:10-1-kinematics:misc:b6891d85', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In a deceleration problem, interchanging the initial and final speeds \\( u \\) and \\( v \\).</p><p><strong>✅ The correct idea:</strong> \\( u \\) is the speed at the start, \\( v \\) the speed at the end. A weak answer swaps them; a strong answer substitutes carefully so that a deceleration comes out as a negative acceleration.</p>", "question": "A car slows from 14 m s⁻¹ to 9 m s⁻¹. In the suvat formulae, \\( u \\) is:", "options": ["14 m s⁻¹ (the initial speed)", "9 m s⁻¹ (the final speed)", "5 m s⁻¹ (the difference)", "either, it makes no difference"]}'::jsonb, '{"answer": 0, "explain": "\\( u \\) is the initial velocity (14), \\( v \\) the final velocity (9); swapping them gives the wrong sign for the acceleration."}'::jsonb),
('additional-maths:10-1-kinematics:tips:fa0a9d08', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tips', 'mcq', 1, '{"readingTitle": "explain — Read the acceleration: calculus or suvat?", "reading": "<p><strong>Before you start, decide which toolkit applies.</strong> If the problem says the acceleration is constant/uniform (or \"decelerates uniformly\"), use the <strong>suvat</strong> formulae. If the velocity or acceleration is given as a <strong>function of \\( t \\)</strong>, the acceleration varies, so you must <strong>differentiate or integrate</strong>.</p><p>In the 2019 speed-bump question, part (a) is constant deceleration (suvat) but part (c) has a cubic velocity — examiners reported that candidates who reached for suvat on part (c) scored nothing.</p>", "question": "The velocity is \\( v = t^2 - 5t + 6 \\). Which method finds the acceleration?", "options": ["Differentiate \\( v \\)", "Use \\( v = u + at \\)", "Use \\( v^2 = u^2 + 2as \\)", "Integrate \\( v \\)"]}'::jsonb, '{"answer": 0, "explain": "Variable acceleration — differentiate: \\( a = 2t - 5 \\)."}'::jsonb),
('additional-maths:10-1-kinematics:tips:ac8750eb', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show your method and give units", "reading": "<p>Kinematics marks are split into method (M) and accuracy (A) marks.</p><p><strong>0 marks:</strong> a bare number such as \"115\" with no working.</p><p><strong>Partial:</strong> correct integration or suvat set-up shown, but no units or a slip in the arithmetic — the M mark is still earned.</p><p><strong>Full marks:</strong> method shown, correct value, and units stated, e.g. distance \\( = 115 \\) m or maximum acceleration \\( = 0.75 \\) m s⁻².</p>", "question": "Why write out the integration before the final number?", "options": ["To earn the method mark even if the arithmetic slips", "It is never necessary", "To use more of the answer space", "To avoid giving units"]}'::jsonb, '{"answer": 0, "explain": "Method (M) marks reward correct visible working, independent of the final value."}'::jsonb),
('additional-maths:10-1-kinematics:tips:a8dee1ff', 'additional-maths', 'additional-maths:10-1-kinematics', '10.1 Kinematics', 'tips', 'mcq', 1, '{"readingTitle": "explain — \"Maximum\" means a turning point", "reading": "<p>To maximise a quantity, set the derivative of <em>that</em> quantity to zero. For a <strong>maximum velocity</strong>, set \\( a = \\frac{dv}{dt} = 0 \\). For a <strong>maximum acceleration</strong>, set \\( \\frac{da}{dt} = 0 \\) — differentiating the acceleration, not the velocity.</p><p>Then confirm it is a maximum (the derivative changes from positive to negative, or the second derivative is negative) and substitute back to state the value, with units.</p>", "question": "To find the maximum acceleration of a particle you set:", "options": ["\\( \\frac{da}{dt} = 0 \\)", "\\( a = 0 \\)", "\\( \\frac{dv}{dt} = 0 \\)", "\\( v = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "Maximum acceleration is a turning point of \\( a \\), so differentiate \\( a \\) and set it to zero."}'::jsonb),
