('additional-maths:10-2-solving-equations-numerically:mcq:71d10a04', 'additional-maths', 'additional-maths:10-2-solving-equations-numerically', '10.2 Solving Equations Numerically', 'mcq', 'mcq', 1, '{"question": "Which is a correct rearrangement of \\( x^3 - x - 7 = 0 \\) for iteration?", "options": ["\\( x_{n+1} = \\sqrt[3]{x_n + 7} \\)", "\\( x_{n+1} = x_n^3 - 7 \\)", "\\( x_{n+1} = \\sqrt[3]{x_n} + 7 \\)", "\\( x_{n+1} = \\frac{7}{x_n^2 - 1} \\) only"]}'::jsonb, '{"answer": 0, "explain": "\\( x^3 = x + 7 \\Rightarrow x = \\sqrt[3]{x + 7} \\), giving \\( x_{n+1} = \\sqrt[3]{x_n + 7} \\)."}'::jsonb),
