('additional-maths:10-2-solving-equations-numerically:tf:8be6700d', 'additional-maths', 'additional-maths:10-2-solving-equations-numerically', '10.2 Solving Equations Numerically', 'tf', 'tf', 1, '{"question": "If \\( \\text{f}(a) \\) and \\( \\text{f}(b) \\) have the same sign, there is guaranteed to be a root between them."}'::jsonb, '{"answer": false, "explain": "You need OPPOSITE signs. The same sign proves nothing — there could be no root, or an even number of roots."}'::jsonb),
